// Sanitizacion incompleta — solo elimina < > sin proteccion XSS real
// Antipatron: sin validacion de longitud, sin run_id, sin esquema
const body = $input.first().json.body || {};

const sanitized = {
  token:      (body.token      || '').replace(/[<>]/g, ''),
  user_id:    (body.user_id    || '').replace(/[<>]/g, ''),
  session_id: body.session_id  || null,
  message:    (body.message    || '').replace(/[<>]/g, ''),
  ts_recibido: new Date().toISOString()
};

// Log sin run_id — antipatron REG-002, REG-006
console.log('Solicitud recibida: ' + JSON.stringify({
  user_id: sanitized.user_id,
  ts: sanitized.ts_recibido
}));

return [{ json: sanitized }];

// Rate limit en memoria de la instancia — no distribuido
// Antipatron: se resetea al reiniciar n8n, no escala horizontalmente
const staticData = $getWorkflowStaticData('global');
const user_id = $input.first().json.user_id || 'anonymous';
const ahora = Date.now();
const VENTANA_MS = 60000; // 1 minuto hardcodeado
const LIMITE = 10;         // hardcodeado

if (!staticData.contadores) staticData.contadores = {};
if (!staticData.contadores[user_id]) {
  staticData.contadores[user_id] = { count: 0, ventana_inicio: ahora };
}

const cnt = staticData.contadores[user_id];
if (ahora - cnt.ventana_inicio > VENTANA_MS) {
  cnt.count = 0;
  cnt.ventana_inicio = ahora;
}
cnt.count++;

return [{ json: { ...$input.first().json, request_count: cnt.count, rate_limit: LIMITE } }];

// Antipatron REG-007, REG-008:
// Logica de dominio (R001-R004) + preparacion del payload HTTP mezclados
// en un unico Code node — imposible testear las reglas de negocio de forma aislada
const body = $input.first().json;
const historial = $('Consultar Historial Usuario').item.json;
const msg = (body.message || '').toLowerCase();

let categoria = 'general';
let prioridad  = 'baja';
let respuesta  = 'Gracias por tu mensaje. Un agente te contactara pronto.';

// R001 — incidente critico
if (msg.includes('urgente') || msg.includes('critico') || msg.includes('emergencia')) {
  categoria = 'incidente';
  prioridad  = 'alta';
  respuesta  = 'Tu caso fue marcado como URGENTE. Un agente senior te atendra en los proximos 15 minutos.';
}
// R002 — facturacion
else if (msg.includes('factura') || msg.includes('pago') || msg.includes('cobro')) {
  categoria = 'facturacion';
  prioridad  = 'media';
  respuesta  = 'Tu consulta de facturacion fue registrada. Te contactaremos en 24 horas.';
}
// R003 — soporte tecnico
else if (msg.includes('error') || msg.includes('falla') || msg.includes('no funciona')) {
  categoria = 'soporte_tecnico';
  prioridad  = 'media';
  respuesta  = 'Recibimos tu reporte de falla. Nuestro equipo tecnico lo revisara en breve.';
}
// R004 — saludo
else if (msg.includes('hola') || msg.includes('buenos') || msg.includes('buenas')) {
  categoria = 'saludo';
  prioridad  = 'baja';
  respuesta  = 'Hola! Bienvenido al soporte. En que puedo ayudarte hoy?';
}

// Armado del payload para la API de tickets MEZCLADO con la clasificacion
// Antipatron: acoplamiento entre logica de dominio y detalles del adaptador externo
const ticket_payload = {
  usuario:         body.user_id,
  sesion:          body.session_id,
  asunto:          categoria,
  nivel_urgencia:  prioridad,
  descripcion:     body.message,
  tickets_previos: historial.tickets_activos || 0,
  canal:           'webhook',
  timestamp:       new Date().toISOString(),
  api_source_token: 'mi-token-secreto-hardcodeado-123'
};

return [{ json: { ...body, categoria, prioridad, respuesta, ticket_payload } }];
